#include <hip/hip_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <algorithm>
#include <vector>

#define HIP_CHECK(call)                                                       \
    do {                                                                      \
        hipError_t err = call;                                                \
        if (err != hipSuccess) {                                              \
            fprintf(stderr, "HIP error: %s at %s:%d\n",                      \
                    hipGetErrorString(err), __FILE__, __LINE__);              \
            exit(1);                                                          \
        }                                                                     \
    } while (0)

constexpr int BLOCK_SIZE = 256;

__global__ void stream_read_kernel(const float4* __restrict__ buf,
                                   float* __restrict__ sink,
                                   size_t n_float4) {
    size_t gid    = blockIdx.x * (size_t)blockDim.x + threadIdx.x;
    size_t stride = (size_t)blockDim.x * gridDim.x;

    float acc = 0.0f;
    for (size_t i = gid; i < n_float4; i += stride) {
        float4 v = buf[i];
        acc += v.x + v.y + v.z + v.w;
    }

    __shared__ float smem[BLOCK_SIZE];
    smem[threadIdx.x] = acc;
    __syncthreads();

    for (int s = BLOCK_SIZE / 2; s > 0; s >>= 1) {
        if (threadIdx.x < (unsigned)s)
            smem[threadIdx.x] += smem[threadIdx.x + s];
        __syncthreads();
    }

    if (threadIdx.x == 0)
        sink[blockIdx.x] = smem[0];
}

int main() {
    const size_t buffer_bytes = 3ULL * 1024 * 1024 * 1024;   // 3 GiB
    const size_t n_float4     = buffer_bytes / sizeof(float4);

    float4* d_buf = nullptr;
    float*  d_sink = nullptr;

    HIP_CHECK(hipMalloc(&d_buf, buffer_bytes));
    HIP_CHECK(hipMemset(d_buf, 0x3f, buffer_bytes));

    hipDeviceProp_t prop;
    HIP_CHECK(hipGetDeviceProperties(&prop, 0));

    const int num_blocks = prop.multiProcessorCount * 16;
    HIP_CHECK(hipMalloc(&d_sink, sizeof(float) * num_blocks));

    // Warmup
    for (int i = 0; i < 5; i++)
        stream_read_kernel<<<num_blocks, BLOCK_SIZE>>>(d_buf, d_sink, n_float4);
    HIP_CHECK(hipDeviceSynchronize());

    // Timed iterations
    const int N_ITER = 30;
    std::vector<float> times(N_ITER);

    for (int i = 0; i < N_ITER; i++) {
        hipEvent_t t0, t1;
        HIP_CHECK(hipEventCreate(&t0));
        HIP_CHECK(hipEventCreate(&t1));

        HIP_CHECK(hipEventRecord(t0));
        stream_read_kernel<<<num_blocks, BLOCK_SIZE>>>(d_buf, d_sink, n_float4);
        HIP_CHECK(hipEventRecord(t1));
        HIP_CHECK(hipEventSynchronize(t1));

        float ms;
        HIP_CHECK(hipEventElapsedTime(&ms, t0, t1));
        times[i] = ms;

        HIP_CHECK(hipEventDestroy(t0));
        HIP_CHECK(hipEventDestroy(t1));
    }

    std::sort(times.begin(), times.end());
    float median_ms = times[N_ITER / 2];

    double bw_gbps = (double)buffer_bytes / ((double)median_ms * 1.0e-3) / 1.0e9;

    printf("HBM_BANDWIDTH_GBPS=%.2f\n", bw_gbps);
    printf("buffer_bytes=%zu\n", buffer_bytes);

    HIP_CHECK(hipFree(d_buf));
    HIP_CHECK(hipFree(d_sink));
    return 0;
}

